struct<persistable> PlayerContainerState:
    PlayerId: string := ""
    MyToken: string := ""

class ConcurrentPlayerManager extends Actor:
    PlayerRegistry: map<string, PlayerContainerState> := {}
    event OnTokensReady: void

    function InitializeConcurrentPlayers(Players: array<string>) <writes>:
        sync:
            for P in Players:
                C := PlayerContainerState{}
                C.PlayerId := P
                C.MyToken := GenerateUniqueToken()
                PlayerRegistry[P] := C

        # Verify uniqueness across all generated tokens
        Tokens := array<string>{}
        for _, State in PlayerRegistry:
            Tokens.append(State.MyToken)

        if AreAllUnique(Tokens):
            OnTokensReady(this)
        else:
            Print("Warning: Duplicate tokens detected during concurrent setup")

    function GenerateUniqueToken() -> string <computes>:
        return "UID_" + RandomString(16)

    function AreAllUnique(A: array<string>) -> bool <computes>:
        Seen := map<string, bool>{}
        for Item in A:
            if Item in Seen:
                return false
            Seen[Item] := true
        return true

