struct<computes> LogRecord:
    Timestamp: float
    Content: string

class ConcurrentTimestampDevice extends creative_device:
    private LogHistory : map<int, LogRecord> = map<int, LogRecord>{}
    private NextIndex : int = 0

    OnReplicatedBeginPlay():void<writes> =
        super.OnReplicatedBeginPlay()
        Print("[REPLICATED] Concurrent logger started")

    OnReplicatedEndPlay():void<writes> =
        super.OnReplicatedEndPlay()
        Print("[REPLICATED] Concurrent logger stopped")

    public LogAndValidate(Message: string):void<writes> =
        # Speculative execution: bind and validate in one step
        if (ValidMessage := len(Message) > 0 and len(Message) <= 128):
            Timestamp := GetSecondsSinceEpoch()
            Record := LogRecord{Timestamp: Timestamp, Content: ValidMessage}
            LogHistory[NextIndex] = Record
            NextIndex += 1
            Print(&"[{Timestamp}] {ValidMessage}")
        else:
            Print("[WARN] Message rejected: invalid length")

    public PurgeOldEntries(MaxAgeSeconds: float):void<writes> =
        CurrentTime := GetSecondsSinceEpoch()
        sync:
            # Parallel cleanup simulation
            for Index, Entry in LogHistory:
                if CurrentTime - Entry.Timestamp > MaxAgeSeconds:
                    LogHistory[Index] = LogRecord{}
            Print("[CLEANUP] Old entries purged")

